cd '/Volumes/4TB SD/ClaudeCode/noethersolve' && python -c "
import json
try:
    with open('results/research_status.json') as f:
        s = json.load(f)
    d = s.get('current_domain') or 'idle'
    p = s.get('current_phase', 'idle')
    n = len(s.get('completed_domains', []))
    r = s.get('domain_results', {})
    passes = sum(1 for v in r.values() if v.get('verdict') == 'PASS')
    total = len(r)
    if r:
        msg = f'Research: {d} [{p}] | {passes}/{total} domains pass | {n} complete'
    else:
        msg = f'Research: {d} [{p}]'
    # Check for escalations needing Claude's attention
    esc_count = 0
    esc_summary = ''
    try:
        with open('results/escalations.jsonl') as ef:
            for line in ef:
                e = json.loads(line)
                if e.get('status') == 'open':
                    esc_count += 1
                    if esc_count <= 3:
                        esc_summary += f' | ESCALATION: {e["domain"]} — {e["reason"]}: {e["details"].get("suggestion", "")}'
    except FileNotFoundError:
        pass
    if esc_count > 0:
        msg += f' | {esc_count} escalation(s) need your attention{esc_summary}'
    print(json.dumps({'hookSpecificOutput': {'hookEventName': 'UserPromptSubmit', 'additionalContext': msg}}))
except FileNotFoundError:
    pass
except Exception:
    pass
" 2>/dev/null || true
